"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["65010"],{59738(s){s.exports=JSON.parse('{"tag":{"label":"152-fz","permalink":"/sysanalyst-kb.github.io/docs/tags/152-fz","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":1,"items":[{"id":"specialization/medtech-regulations","title":"\u0420\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0430 \u0432 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0435 (323-\u0424\u0417, 152-\u0424\u0417, \u043E\u0431\u043E\u0440\u043E\u0442 \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432)","description":"\u041C\u0435\u0434\u0438\u0446\u0438\u043D\u0430 \u2014 \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0445 \u043E\u0442\u0440\u0430\u0441\u043B\u0435\u0439. \u0422\u0440\u0438 \u0441\u0442\u043E\u043B\u043F\u0430: 323-\u0424\u0417 (\u043E\u0445\u0440\u0430\u043D\u0430 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F, \u042D\u041C\u041A, \u0442\u0435\u043B\u0435\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0430), 152-\u0424\u0417 (\u041F\u0414 \u043E\u0441\u043E\u0431\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438), \u043F\u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u2116 1275 (\u0415\u0413\u0418\u0421\u0417). \u0412\u0441\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u043E \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435 \u2014 \u041F\u0414 \u043E\u0441\u043E\u0431\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u0437\u0430\u0449\u0438\u0442\u0430 \u0423\u0417-1). \u041B\u044E\u0431\u0430\u044F \u041C\u0418\u0421 \u0434\u043E\u043B\u0436\u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u043A \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0435 \u041F\u0414 \u0438, \u0435\u0441\u043B\u0438 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0432\u0440\u0430\u0447\u0435\u0431\u043D\u044B\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F, \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043C\u0435\u0434\u0438\u0437\u0434\u0435\u043B\u0438\u0435 (\u043A\u043B\u0430\u0441\u0441\u044B \u0440\u0438\u0441\u043A\u0430 2a, 2b, 3). \u0428\u0442\u0440\u0430\u0444\u044B \u0437\u0430 \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0438\u044F \u2014 \u0434\u043E 300 \u0442\u044B\u0441. \u0440\u0443\u0431. \u043F\u043E \u041A\u043E\u0410\u041F, \u0443\u0433\u043E\u043B\u043E\u0432\u043D\u0430\u044F \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u2014 \u0437\u0430 \u0440\u0430\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u0435 \u041F\u0414 (\u0441\u0442. 137 \u0423\u041A \u0420\u0424).","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-regulations"}],"unlisted":false}}')}}]);